argv:
cat > .pi-eval-access-blackbox.zig <<'EOF'
const std = @import("std");
const app = @import("src/main.zig");

fn event(id: u32, role: app.Role, action: app.Action, level: u8, cost: u32) app.Event {
    return .{ .id = id, .role = role, .action = action, .level = level, .resource_cost = cost, .label = [_]u8{'x'} ** 48, .provenance = [_]u8{'y'} ** 80 };
}

test "ordered access policy semantics" {
    const rules = [_]app.Rule{
        .{ .role = .guest, .action = .read, .min_level = 0, .allow = true, .weight = 2 },
        .{ .role = .guest, .action = .read, .min_level = 3, .allow = false, .weight = 9 },
        .{ .role = .user, .action = .deploy, .min_level = 4, .allow = true, .weight = 7 },
        .{ .role = .admin, .action = .purge, .min_level = 8, .allow = true, .weight = 11 },
    };
    const events = [_]app.Event{
        event(10, .guest, .read, 5, 100),
        event(11, .user, .deploy, 3, 100),
        event(12, .user, .deploy, 4, 50),
        event(13, .admin, .purge, 8, 10),
        event(14, .auditor, .read, 9, 1),
    };
    const summary = app.evaluateAccess(rules[0..], events[0..]);
    try std.testing.expectEqual(@as(usize, 3), summary.allowed);
    try std.testing.expectEqual(@as(usize, 2), summary.denied);
    try std.testing.expectEqual(@as(u64, 660), summary.weighted_cost);
    try std.testing.expectEqual(@as(u64, 5041), summary.checksum);
}
EOF
zig test .pi-eval-access-blackbox.zig -OReleaseFast
